1	const PROCESSING_FEE = 5;
2	
3	interface Item {
4	  type: string;
5	  material: string;
6	  enchantment: number;
7	  cursed: boolean;
8	}
9	
10	const BASE_PREMIUMS: Record<string, number> = {
11	  sword: 100,
12	  amulet: 60,
13	  staff: 80,
14	  potion: 40,
15	  rune: 25,
16	  moonstone: 25,
17	};
18	
19	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
20	const BLOCK_SIZE = 3;
21	const BLOCK_PREMIUM = 60;
22	
23	const basePremium = (item: Item): number => BASE_PREMIUMS[item.type] ?? 0;
24	
25	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
26	
27	const itemPremium = (item: Item): number => {
28	  const base = basePremium(item);
29	  const curseSurcharge = item.cursed ? base * 0.5 : 0;
30	  const enchantmentSurcharge = item.enchantment >= 5 ? base * 0.3 : 0;
31	  return base + curseSurcharge + enchantmentSurcharge;
32	};
33	
34	const componentBlockPremium = (type: string, count: number): number =>
35	  count === BLOCK_SIZE ? BLOCK_PREMIUM : count * (BASE_PREMIUMS[type] ?? 0);
36	
37	const countByType = (items: Item[]): Record<string, number> =>
38	  items.reduce<Record<string, number>>((counts, item) => {
39	    counts[item.type] = (counts[item.type] ?? 0) + 1;
40	    return counts;
41	  }, {});
42	
43	const componentsPremium = (components: Item[]): number =>
44	  Object.entries(countByType(components)).reduce(
45	    (sum, [type, count]) => sum + componentBlockPremium(type, count),
46	    0
47	  );
48	
49	const itemsPremium = (items: Item[]): number => {
50	  const components = items.filter(isComponent);
51	  const nonComponents = items.filter((item) => !isComponent(item));
52	  const mainPremium = nonComponents.reduce(
53	    (sum, item) => sum + itemPremium(item),
54	    0
55	  );
56	  return mainPremium + componentsPremium(components);
57	};
