59	const DEDUCTIBLE = 100;
60	
61	export const claim = (
62	  policy: { items: Item[] },
63	  damages: { itemType: string; amount: number }[]
64	): { payout: number; remainingCap: number } => {
65	  const payout = damages.reduce((sum, d) => {
66	    const item = policy.items.find((i) => i.type === d.itemType);
67	    const reimbursement = item && item.enchantment >= 8 ? d.amount * 0.5 : d.amount;
68	    return sum + Math.max(0, reimbursement - DEDUCTIBLE);
69	  }, 0);
70	  return { payout, remainingCap: 0 };
71	};
