73	export const quote = (
74	  customer: { yearsWithMHPCO: number },
75	  items: Item[],
76	  isFollowUp: boolean
77	): number => {
78	  const premium = itemsPremium(items);
79	  const policyBasePremium = items.reduce((sum, item) => sum + basePremium(item), 0);
80	  const firstInsurance = policyBasePremium * 0.1;
81	  const loyaltyDiscount = customer.yearsWithMHPCO >= 2 ? policyBasePremium * 0.2 : 0;
82	  const followUpDiscount = isFollowUp ? policyBasePremium * 0.15 : 0;
83	  return Math.ceil(premium + firstInsurance - loyaltyDiscount - followUpDiscount + PROCESSING_FEE);
