const DEDUCTIBLE = 100;
const HIGH_ENCHANTMENT_THRESHOLD = 8;
const HIGH_ENCHANTMENT_REIMBURSEMENT_RATE = 0.5;

const reimbursableAmount = (policyItem: Item | undefined, damageAmount: number): number => {
  if (policyItem && policyItem.enchantment >= HIGH_ENCHANTMENT_THRESHOLD) {
    return damageAmount * HIGH_ENCHANTMENT_REIMBURSEMENT_RATE;
  }
  return damageAmount;
};

export const claim = (
  policy: { items: Item[] },
  damages: { itemType: string; amount: number }[]
): { payout: number; remainingCap: number } => {
  const payout = damages.reduce((sum, damage) => {
    const policyItem = policy.items.find((item) => item.type === damage.itemType);
    const reimbursement = reimbursableAmount(policyItem, damage.amount);
    return sum + Math.max(0, reimbursement - DEDUCTIBLE);
  }, 0);
  return { payout, remainingCap: 0 };
};

