72	  damages: { itemType: string; amount: number }[]
73	): { payout: number; remainingCap: number } => {
74	  const payout = damages.reduce((sum, damage) => {
75	    const policyItem = policy.items.find((item) => item.type === damage.itemType);
76	    const reimbursement = reimbursableAmount(policyItem, damage.amount);
77	    return sum + Math.max(0, reimbursement - DEDUCTIBLE);
78	  }, 0);
79	  return { payout, remainingCap: 0 };
80	};
