82	export const quote = (
83	  customer: { yearsWithMHPCO: number },
84	  items: Item[],
85	  isFollowUp: boolean
86	): number => {
87	  const premium = itemsPremium(items);
88	  const policyBasePremium = items.reduce((sum, item) => sum + basePremium(item), 0);
89	  const firstInsurance = policyBasePremium * 0.1;
90	  const loyaltyDiscount = customer.yearsWithMHPCO >= 2 ? policyBasePremium * 0.2 : 0;
91	  const followUpDiscount = isFollowUp ? policyBasePremium * 0.15 : 0;
92	  return Math.ceil(premium + firstInsurance - loyaltyDiscount - followUpDiscount + PROCESSING_FEE);
93	};
